const input = $input.item.json.body || $input.item.json;

// Extração de variáveis de custo se disponiveis
const materialCost = input.custo_material || 0;
const laborCost = input.custo_mao_de_obra || 0;
const transportCost = input.custo_deslocamento || 0;
const gastronomyCostMultiplier = input.alta_urgencia_gastronomia ? 1.25 : 1.0; // Urgência (chapas, fritadeiras)

const tipo_cliente = input.tipo_cliente || 'condominio';
const prioridade = input.prioridade || 'normal';

// Soma de custos internos (Custo Operacional Estimado)
let custo_operacional_estimado = (materialCost + laborCost + transportCost) * gastronomyCostMultiplier;

// Se faltar dados críticos e não tiver custo preenchido, define Avaliação Técnica
if (custo_operacional_estimado === 0) {
    return {
        status: "Sob Avaliação Técnica",
        mensagem: "Dados críticos ausentes. Requer Avaliação Técnica do Tecnólogo Responsável."
    };
}

// Aplicação de margens (35% e 45%)
let preco_minimo_sem_prejuizo = custo_operacional_estimado * 1.35;
let preco_comercial_recomendado = custo_operacional_estimado * 1.45;

// Garantia de Piso
let piso = 450; // Padrão
if (prioridade === 'emergencia' || prioridade === 'alta') {
    piso = 650;
}

// Aplicando Piso
if (preco_comercial_recomendado < piso) {
    preco_comercial_recomendado = piso;
}
if (preco_minimo_sem_prejuizo < piso * 0.85) {
    preco_minimo_sem_prejuizo = piso * 0.85;
}

// Formas de Pagamento
const preco_comercial_recomendado_pix = preco_comercial_recomendado;
const preco_comercial_recomendado_cartao = preco_comercial_recomendado * 1.09;

// Imposto - Sempre imposto_estimado_percentual
const imposto_estimado_percentual = 0.06; // Pendente de validação contábil

// Retorno: Separando a visão do cliente da visão interna (para não expor custos)
return {
    proposta: {
        preco_minimo_sem_prejuizo: parseFloat(preco_minimo_sem_prejuizo.toFixed(2)),
        preco_comercial_recomendado_pix: parseFloat(preco_comercial_recomendado_pix.toFixed(2)),
        preco_comercial_recomendado_cartao: parseFloat(preco_comercial_recomendado_cartao.toFixed(2)),
        imposto_estimado_percentual: imposto_estimado_percentual,
        observacao_imposto: "Pendência de validação contábil",
        observacao_tecnica: "Valores sujeitos a Avaliação Técnica do Tecnólogo Responsável da DL Soluções."
    },
    auditoria_interna: {
        custo_operacional_estimado: parseFloat(custo_operacional_estimado.toFixed(2)),
        urgencia_gastronomia_aplicada: input.alta_urgencia_gastronomia || false,
        piso_acionado: preco_comercial_recomendado === piso
    }
};
